class Solution:
    def minimumSubarrayLength(self, nums: List[int], k: int) -> int:
        n = len(nums)
        min_len = -1

        for i in range(n):
            current_or = 0
            for j in range(i, n):
                current_or |= nums[j]
                if current_or >= k:
                    if min_len == -1 or (j - i + 1) < min_len:
                        min_len = j - i + 1
                    break

        return min_len
